//! Automated call testing applications.
//!
//! Port of app_test.c from Asterisk C. Provides TestClient() and
//! TestServer() applications for automated call quality testing.
//! The server answers and plays tones, the client calls and measures
//! audio quality, producing a report file.

use crate::{DialplanApp, PbxExecResult};
use asterisk_core::channel::Channel;
use tracing::{info, warn};

/// Test report generated by TestClient.
#[derive(Debug, Clone, Default)]
pub struct TestReport {
    /// Test identifier.
    pub test_id: String,
    /// Number of audio frames sent.
    pub frames_sent: u64,
    /// Number of audio frames received.
    pub frames_received: u64,
    /// Number of lost frames.
    pub frames_lost: u64,
    /// Percentage of frames received.
    pub receive_pct: f64,
    /// Jitter measurement (ms).
    pub jitter_ms: f64,
}

impl TestReport {
    /// Format report for file output.
    pub fn to_string_report(&self) -> String {
        format!(
            "TestID: {}\nFramesSent: {}\nFramesRecv: {}\nFramesLost: {}\nRecvPct: {:.1}%\nJitter: {:.1}ms\n",
            self.test_id,
            self.frames_sent,
            self.frames_received,
            self.frames_lost,
            self.receive_pct,
            self.jitter_ms,
        )
    }
}

/// The TestServer() dialplan application.
///
/// Usage: TestServer()
///
/// Answers the channel and plays a sequence of test tones (1004 Hz milliwatt)
/// that the TestClient can measure. Runs until the client hangs up.
pub struct AppTestServer;

impl DialplanApp for AppTestServer {
    fn name(&self) -> &str {
        "TestServer"
    }

    fn description(&self) -> &str {
        "Automated call test server - plays test tones"
    }
}

