/// The TestClient() dialplan application.
///
/// Usage: TestClient(testid)
///
/// Calls out, receives test tones from TestServer, measures audio
/// quality (frame loss, jitter), and writes a report file.
///
/// Report is written to /var/log/asterisk/testreport_<testid>.txt
pub struct AppTestClient;

impl DialplanApp for AppTestClient {
    fn name(&self) -> &str {
        "TestClient"
    }

    fn description(&self) -> &str {
        "Automated call test client - measures audio quality"
    }
}

impl AppTestClient {
    /// Execute the TestClient application.
    pub async fn exec(channel: &mut Channel, args: &str) -> PbxExecResult {
        let test_id = args.trim();

        if test_id.is_empty() {
            warn!("TestClient: requires test ID argument");
            return PbxExecResult::Failed;
        }

        info!("TestClient: channel '{}' test '{}'", channel.name, test_id);

        // In a real implementation:
        // 1. Set format to slin
        // 2. Read audio frames from channel
        // 3. Track sequence numbers, measure loss and jitter
        // 4. After hangup, write report file

        PbxExecResult::Success
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_report_format() {
        let report = TestReport {
            test_id: "test1".to_string(),
            frames_sent: 1000,
            frames_received: 980,
            frames_lost: 20,
            receive_pct: 98.0,
            jitter_ms: 5.2,
        };
        let s = report.to_string_report();
        assert!(s.contains("TestID: test1"));
        assert!(s.contains("FramesLost: 20"));
    }

    #[tokio::test]
    async fn test_server_exec() {
        let mut channel = Channel::new("SIP/test-001");
        let result = AppTestServer::exec(&mut channel, "").await;
        assert_eq!(result, PbxExecResult::Success);
    }

    #[tokio::test]
    async fn test_client_exec() {
        let mut channel = Channel::new("SIP/test-001");
        let result = AppTestClient::exec(&mut channel, "test1").await;
        assert_eq!(result, PbxExecResult::Success);
    }
}
